想必phper对date()函数不会陌生，date('Y-m-d H:i:s')是常见的用法。date扩展代码行数不少，而且一大块宏让人摸不着头脑。先根据自己的思路写一个吧，给PHP添加一个打印当前时间格式化形式的函数。函数原型位于ext/standard/basic_functions.stub.php，function pmydate(string $value): void {}函数接收一个格式化字符串，仅支持Y、m、d、H、i、s几种格式，没有返回值，直接输出结果。
// ext/standard/basic_functions.stub.php function pmydate(string $value): void {} 扩展代码：
// ext/standard/basic_functions.c PHP_FUNCTION(pmydate) { zval *zv_ptr; php_printf(&#34;passed %d parameters to the function: pmydate
&#34;, ZEND_NUM_ARGS()); if (zend_parse_parameters(ZEND_NUM_ARGS(), &#34;z&#34;, &amp;zv_ptr) == FAILURE) { return; } if (Z_TYPE_P(zv_ptr) != IS_STRING) { php_printf(&#34;Expect one string argument
&#34;); return; } time_t now = time(0); struct tm *lt = localtime(&amp;now); char c; int val; char type; char prev = &#39;\0&#39;; for (int i = 0; i &lt; (*zv_ptr).value.str-&gt;len; i++) { c = (*zv_ptr).value.str-&gt;val[i]; type = &#39;s&#39;; switch (c) { case &#39;Y&#39;: val = lt-&gt;tm_year + 1900; type = &#39;i&#39;; break; case &#39;m&#39;: val = lt-&gt;tm_mon + 1; break; case &#39;d&#39;: val = lt-&gt;tm_mday; break; case &#39;H&#39;: val = lt-&gt;tm_hour; break; case &#39;i&#39;: val = lt-&gt;tm_min; break; case &#39;s&#39;: val = lt-&gt;tm_sec; break; case &#39;\&#39;: val = c; type = &#39;\0&#39;; break; default: val = c; type = &#39;c&#39;; } if (prev != &#39;\&#39;) { switch (type) { case &#39;s&#39;: php_printf(&#34;%02d&#34;, val); break; case &#39;i&#39;: php_printf(&#34;%d&#34;, val); break; case &#39;c&#39;: php_printf(&#34;%c&#34;, val); break; default:; } } else { php_printf(&#34;%c&#34;, c); } prev = c; } php_printf(&#34;
&#34;); } 用法如下：
$ ./output/bin/php -r &#39;pmydate(&#34;Y-m-d H:i:s \Y-\m-\d \H:\i:\s&#34;);&#39; passed 1 parameters to the function: pmydate 2025-01-08 00:00:00 Y-m-d H:i:s 定义函数： 使用PHP_FUNCTION宏封装函数名； 解释参数：zv_ptr是一个指针变量，指向zval类型，zval是PHP变量类型；php_printf(&quot;passed %d parameters to the function: pmydate
&quot;, ZEND_NUM_ARGS())仅用于查看函数参数数量；zend_parse_parameters(ZEND_NUM_ARGS(), &quot;z&quot;, &amp;zv_ptr)解释函数参数到zv_ptr指针，如果解释参数失败，直接返回； 判断参数类型：Z_TYPE_P(zv_ptr)获取解释后的zv_ptr指向的参数类型，如果不是IS_STRING类型，返回； 获取时间：使用C语言的时间函数获取当前时间，保存到指向struct tm类型的指针中； 声明临时变量：c保存当前指向的字节，val保存格式串对应字节表示的时间，type表示当前字节应该在输出时以什么类型来处理，prev保存上一个字节； 遍历字符串参数：由于要接收一个格式化字符串，因此遍历的数据位于(*zv_ptr).value.str中，(*zv_ptr)就是格式化字符串；(*zv_ptr).value是zend_value2.类型，实际上就是一个union，保存具体的参数；字符串参数当然就要通过zend_value的str字段来获取了； 逐个获取字符串参数中的字节：(*zv_ptr).value.str是指针，指向zend_string类型，zend_string同时也是一个struct，字符串的字节实际保存在zend_string的val字段中，因此(*zv_ptr).value.str-&gt;val[i]指向单个字节； 根据字符串参数的字节获取对应的时间，其中\字符特殊处理一下，前一个字节为\时，当前字符不作解释； 其中大片的switch分支不作详细解释，应该很好理解； 为什么不使用printf而要使用php_printf？因为PHP有多种SAPI，如果只是使用printf只会默认在控制台输出，封装的php_printf则会将数据保存到缓冲中，根据不同的SAPI写入不同的输出流；

Stack Machines，感觉不翻译看起来会顺眼一点，翻译成栈机感觉怪怪的。该文章总结自Igor Wiedler的Stack Machines系列文章，可惜他很久没贡献过代码以及没更新过博客了。先贴代码，到时候再写文章，可能需要一段时间来消化这个系列。
&lt;?php // php 8.2 /** * 操作符优先级以及结合性 */ const operators = [ &#39;+&#39; =&gt; [&#39;precedence&#39; =&gt; 0, &#39;associativity&#39; =&gt; &#39;left&#39;], &#39;-&#39; =&gt; [&#39;precedence&#39; =&gt; 0, &#39;associativity&#39; =&gt; &#39;left&#39;], &#39;*&#39; =&gt; [&#39;precedence&#39; =&gt; 1, &#39;associativity&#39; =&gt; &#39;left&#39;], &#39;/&#39; =&gt; [&#39;precedence&#39; =&gt; 1, &#39;associativity&#39; =&gt; &#39;left&#39;], &#39;%&#39; =&gt; [&#39;precedence&#39; =&gt; 1, &#39;associativity&#39; =&gt; &#39;left&#39;], ]; /** * 栈机执行器 * @param array $ops * @return mixed|void */ function execute(array $ops) { $labels = []; $vars = []; $calls = new SplStack(); $stack = new SplStack(); // 这里需要先获取所有 label，以防之后的 jmp/call 之类的指令找不到 label foreach ($ops as $ip =&gt; $op) { if (preg_match(&#39;/^label\((.+)\)$/&#39;, $op, $match)) { $label = $match[1]; $labels[$label] = $ip; } } for ($ip = 0; $ip &lt; count($ops); $ip++) { $op = $ops[$ip]; if (is_numeric($op)) { $stack-&gt;push((int)$op); continue; } // 格式：label(main)，名为 main 的标签 // 移到上面，防止 jmp 找不到 对应的 $labels[$label]; if (preg_match(&#39;/^label\((.+)\)$/&#39;, $op, $match)) { // $label = $match[1]; // $labels[$label] = $ip; continue; } // 格式：jmp(main)，跳转到 main 标签 if (preg_match(&#39;/^jmp\((.+)\)$/&#39;, $op, $match)) { $label = $match[1]; $ip = $labels[$label]; continue; } // 格式：jz(main)，如果栈顶元素为 0，则跳转到 main 标签 if (preg_match(&#39;/^jz\((.+)\)$/&#39;, $op, $match)) { $label = $match[1]; if ($stack-&gt;pop() === 0) { $ip = $labels[$label]; } continue; } // 格式：jnz(main)，如果栈顶元素不为 0，则跳转到 main 标签 if (preg_match(&#39;/^jnz\((.+)\)$/&#39;, $op, $match)) { $label = $match[1]; if ($stack-&gt;pop() !== 0) { $ip = $labels[$label]; } continue; } // 格式：call(printstr)，函数调用 if (preg_match(&#39;/^call\((.+)\)$/&#39;, $op, $match)) { $label = $match[1]; $calls-&gt;push([$ip, $vars]); $ip = $labels[$label]; continue; } // 格式：value !var(varname)，声明变量并赋值为 $stack 顶的元素 if (preg_match(&#39;/^!var\((.+)\)$/&#39;, $op, $match)) { $var = $match[1]; $vars[$var] = $stack-&gt;pop(); continue; } // 格式：var(varname) if (preg_match(&#39;/^var\((.+)\)$/&#39;, $op, $match)) { $var = $match[1]; $stack-&gt;push($vars[$var]); continue; } switch ($op) { case &#39;+&#39;: $stack-&gt;push($stack-&gt;pop() + $stack-&gt;pop()); break; case &#39;-&#39;: $n = $stack-&gt;pop(); $stack-&gt;push($stack-&gt;pop() - $n); break; case &#39;*&#39;: $stack-&gt;push($stack-&gt;pop() * $stack-&gt;pop()); break; case &#39;/&#39;: $n = $stack-&gt;pop(); $stack-&gt;push($stack-&gt;pop() / $n); break; case &#39;%&#39;: $n = $stack-&gt;pop(); $stack-&gt;push($stack-&gt;pop() % $n); break; case &#39;.&#39;: // 输出文本 echo chr($stack-&gt;pop()); break; case &#39;dup&#39;: // 复制 $stack-&gt;push($stack-&gt;top()); break; case &#39;ret&#39;: // 函数 return list($ip, $vars) = $calls-&gt;pop(); break; case &#39;.num&#39;: // 输出数字本身 echo $stack-&gt;pop(); break; default: throw new InvalidArgumentException(sprintf(&#39;Invalid operation: %s&#39;, $op)); } } if (count($stack) &gt; 0) { return $stack-&gt;top(); } } /** * shunting yard 算法，将中缀表达式转换为后缀表达式 * @param array $tokens * @param array $operators * @return array */ function shunting_yard(array $tokens, array $operators): array { $stack = new SplStack(); // 优先级低的先入栈 $output = new SplQueue(); foreach ($tokens as $token) { if (is_numeric($token)) { $output-&gt;enqueue($token); } elseif (isset($operators[$token])) { $operator1 = $token; // 如果栈上已经存在操作符，且当前操作符比栈顶操作符优先级低，则入队栈顶操作符 while ( has_operator($stack, $operators) &amp;&amp; ($operator2 = $stack-&gt;top()) &amp;&amp; has_lower_precedence($operator1, $operator2, $operators) ) { $output-&gt;enqueue($stack-&gt;pop()); } $stack-&gt;push($operator1); } elseif (&#39;(&#39; === $token) { $stack-&gt;push($token); } elseif (&#39;)&#39; === $token) { while (count($stack) &gt; 0 &amp;&amp; &#39;(&#39; !== $stack-&gt;top()) { $output-&gt;enqueue($stack-&gt;pop()); } if (count($stack) === 0) { throw new InvalidArgumentException(sprintf(&#39;Mismatched parenthesis in input: %s&#39;, json_encode($tokens))); } // pop off &#39;(&#39; $stack-&gt;pop(); } else { throw new InvalidArgumentException(sprintf(&#39;Invalid token: %s&#39;, $token)); } } while (has_operator($stack, $operators)) { $output-&gt;enqueue($stack-&gt;pop()); } if (count($stack) &gt; 0) { throw new InvalidArgumentException(sprintf(&#39;Mismatched parenthesis or misplaced number in input: %s&#39;, json_encode($tokens))); } return iterator_to_array($output); } /** * 栈上是否存在操作符 * @param SplStack $stack * @param array $operators * @return bool */ function has_operator(SplStack $stack, array $operators): bool { return count($stack) &gt; 0 &amp;&amp; ($top = $stack-&gt;top()) &amp;&amp; isset($operators[$top]); } /** * 判断操作符 $operator1 是否比 $operator2 优先级低 * @param $operator1 * @param $operator2 * @param array $operators * @return bool */ function has_lower_precedence($operator1, $operator2, array $operators): bool { $operator1_info = $operators[$operator1]; $operator2_info = $operators[$operator2]; return (&#39;left&#39; === $operator1_info[&#39;associativity&#39;] &amp;&amp; $operator1_info[&#39;precedence&#39;] === $operator2_info[&#39;precedence&#39;]) || $operator1_info[&#39;precedence&#39;] &lt; $operator2_info[&#39;precedence&#39;]; } /** * execute 测试函数 * @param string $code * @param string $name * @return void */ function execute_test(string $code = &#39;&#39;, string $name = &#39;&#39;): void { $ops = preg_split(&#39;/\s/&#39;, preg_replace(&#39;/^\s*#.*$/m&#39;, &#39;&#39;, $code), -1, PREG_SPLIT_NO_EMPTY); $res = execute($ops); echo &#34;
execute ret: 	&#34;; print_r($res); echo &#34;
************************************************************	{$name}
&#34;; } /** * shunting_yard 测试函数 * @param string $code * @param string $name * @return void */ function shunting_yard_test(string $code = &#39;&#39;, string $name = &#39;&#39;): void { $ops = preg_split(&#39;/\s/&#39;, preg_replace(&#39;/^\s*#.*$/m&#39;, &#39;&#39;, $code), -1, PREG_SPLIT_NO_EMPTY); $res = shunting_yard($ops, operators); print_r($res); echo &#34;
************************************************************	{$name}
&#34;; } if ($_SERVER[&#39;PHP_SELF&#39;] === __FILE__) { // execute() test $rpn = &#39;2 3 * 1 +&#39;; execute_test($rpn, &#39;execute()&#39;); // shunting_yard() test $rpn = &#39;1 + 2 * 3&#39;; shunting_yard_test($rpn, &#39;shunting_yard()&#39;); // execute() &amp;&amp; shunting_yard() test $rpn = &#39;2 3 * 1 +&#39;; execute_test($rpn, &#39;execute()&#39;); shunting_yard_test($rpn, &#39;shunting_yard()&#39;); // io test $code = &#39;104 . 101 . 108 . 108 . 111 . 44 . 32 . 119 . 111 . 114 . 108 . 100 . 10 . 10&#39;; execute_test($code, &#39;io&#39;); // dup test $code = &#39;2 dup 5 + *&#39;; execute_test($code, &#39;dup&#39;); // label &amp;&amp; jmp &amp;&amp; jz test $code = &#39; 0 10 100 108 114 111 119 32 44 111 108 108 101 104 label(loop) dup jz(end) . jmp(loop) label(end)&#39;; execute_test($code, &#39;label &amp;&amp; jmp &amp;&amp; jz&#39;); // use regular expression to strip whitespace $code = &#39;1 2 +&#39;; execute_test($code, &#39;strip whitespace&#39;); // strip comments $code = &#39;1 # 这是一个注释 1 2 # 这是一个注释 2 +&#39;; execute_test($code, &#39;comments&#39;); // calls $code = &#39; jmp(start) label(printstr) label(loop) dup jz(end) . jmp(loop) label(end) call(test) ret label(test) 104 . 101 . 108 . 108 . 111 . 44 . 32 . 119 . 111 . 114 . 108 . 100 . 10 . 0 ret label(start) 0 10 100 108 114 111 119 32 44 111 108 108 101 104 call(printstr) &#39;; execute_test($code, &#39;calls&#39;); // variables：从栈上 pop 一个值并保存到变量 varname，!var(varname)，例如“42 !var(answer)”；将 varname 的值 push 到栈上，var(varname)，例如“var(answer)” $code = &#39; # i = 97 # ascii(97) is a 97 !var(i) label(loop) # print i # i++ # jump if i == 123 # ascii(122) is z var(i) . var(i) 1 + !var(i) var(i) 123 - dup jnz(loop) # print 
 10 . &#39;; execute_test($code, &#39;variables&#39;); // variables 2 $code = &#39; # define vars 10 !var(i) 0 !var(p) 1 !var(n) 0 !var(tmp) # output i prev var(i) .num 32 . var(p) .num 10 . # output i n var(i) .num 32 . var(n) .num 10 . label(next) var(i) jz(end) # tmp = n + p # p = n # n = tmp var(p) var(n) + !var(tmp) var(n) !var(p) var(tmp) !var(n) ## output i n var(i) .num 32 . var(n) .num 10 . # i-- var(i) 1 - !var(i) # print ... 105 . 61 . var(i) .num 46 . 46 . 46 . 10 . var(i) jmp(next) label(end) &#39;; execute_test($code, &#39;variables 2&#39;); // stack frame $code = &#39; jmp(start) 88 !var(i) label(foo) 5 !var(i) var(i) .num ret label(start) 11 !var(i) call(foo) var(i) .num var(i) .num &#39;; execute_test($code, &#39;stack frame&#39;); }

命令行覆盖刷新输出的效果如下图。
覆盖刷新的原理：删除已输出字符（用空白字符屏蔽），重新输出新字符。
删除字符需要用到一个特殊字符\b退格符。注意：在很多语言里语言\b退格符跟键盘上的 Backspace 键不太一样，退格符仅仅是回退，并不会删除字符，因此回退后还需要使用一个空白字符覆盖原有字符，才能完成覆盖刷新功能。示例如下：
// go 1.16 package main import ( &#34;fmt&#34; &#34;math/rand&#34; &#34;time&#34; ) func str() string { rand.Seed(time.Now().UnixNano()) strLen := rand.Intn(50) chars := &#34;abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRST0123456789&#34; var ret []byte for i := 0; i &lt; strLen; i++ { ret = append(ret, chars[rand.Intn(len(chars))]) } return string(ret) } func clear(s string) { for i := 0; i &lt; len(s); i++ { fmt.Print(&#34;\b \b&#34;) } } func main() { for i := 0; i &lt; 100; i++ { s := str() fmt.Print(s) time.Sleep(time.Millisecond * 200) clear(s) } } 在 Go 语言中，其实fmt.Print(&quot;\b \b&quot;)有些多余，只需要fmt.Print(&quot;\b&quot;)即可。如果不确定使用的语言\b的行为如何，就统一用\b \b。
在 ASCII 中，除了\b外，还有一个\r回车符也有相似能力。因此我们还可以将func clear(s string)函数修改成如下形式：
// go 1.16 func clear(s string) { fmt.Print(&#34;\r&#34;) for i := 0; i &lt; len(s); i++ { fmt.Print(&#34; &#34;) } fmt.Print(&#34;\r&#34;) } 有某些语言里可能没有\b转义字符，例如 PHP，可以通过字符编码获取退格字符，编码为8。因此，在 PHP 中，可以将clear函数改成如下形式。
&lt;?php // php7.1 function clear($str) { for ($i = 0; $i &lt; strlen($str); $i++) { echo chr(8), &#39; &#39;, chr(8); } }

虚拟机是由软件实现的计算机。
以下是一个由 JavaScript 实现的虚拟机。
let virtualMachine = function(program) { let programCounter = 0; let stack = []; let stackPointer = 0; while (programCounter &lt; program.length) { let currentInstruction = program[programCounter]; switch (currentInstruction) { case &#39;PUSH&#39;: stack[stackPointer] = program[programCounter+1]; stackPointer++; programCounter++; break; case &#39;ADD&#39;: right = stack[stackPointer-1] stackPointer--; left = stack[stackPointer-1] stackPointer--; stack[stackPointer] = left + right; stackPointer++; break; case &#39;MINUS&#39;: right = stack[stackPointer-1] stackPointer--; left = stack[stackPointer-1] stackPointer--; stack[stackPointer] = left - right; stackPointer++; break; } programCounter++; } console.log(&#34;stacktop: &#34;, stack[stackPointer-1]); } let program = [ &#39;PUSH&#39;, 3, &#39;PUSH&#39;, 4, &#39;ADD&#39;, &#39;PUSH&#39;, 5, &#39;MINUS&#39; ]; virtualMachine(program);

生产者/消费者模型 简单来说，生产者生产一些数据，然后放到队列中，同时消费者从队列中取数据。这样就让生产和消费变成了异步的两个过程。当队列中没有数据时，消费者就进入饥饿的等待中；而队列中数据已满时，生产者则面临因产品积压导致 CPU 被剥夺的问题。
package main import ( &#34;fmt&#34; &#34;os&#34; &#34;os/signal&#34; &#34;syscall&#34; &#34;time&#34; ) // 生产者 func Producer(factor int, out chan &lt;- int) { for i := 0; ; i++ { out &lt;- i*factor time.Sleep(time.Second) } } // 消费者 func Consumer(in &lt;- chan int) { for v := range in { fmt.Println(v) } } func main() { ch := make(chan int, 64) go Producer(3, ch) go Producer(5, ch) go Consumer(ch) // Ctrl+C 退出 sig := make(chan os.Signal, 1) signal.Notify(sig, syscall.SIGINT, syscall.SIGTERM) fmt.Printf(&#34;quit (%v)\n&#34;, &lt;- sig) } 订阅/发布模型 订阅/发布(publish-subscribe)模型跟生产者/消费者模型有很多相似之处，发布者好比生产者，订阅者好比消费者。生产者和消费者是 M:N 的关系。而在传统生产者/消费者模型中，是将消息发送到一个队列中，而发布/订阅模型则是将消息发布给一个主题。
// pubsub/pubsub.go package pubsub import ( &#34;sync&#34; &#34;time&#34; ) type ( subscriber chan interface{} // 订阅者为一个通道 topicFunc func(v interface{}) bool // 主题为一个过滤器 ) type Publisher struct { m sync.RWMutex // 读写锁 buffer int // 订阅队列的缓存大小，如果订阅者通道中的消息超过 buffer，则会丢失该消息 timeout time.Duration // 发布超时时间 subscribers map[subscriber]topicFunc // 订阅者列表 } // 构建一个发布者对象，可以设置发布超时时间和发布队列的长度 func NewPublisher(publishTimeout time.Duration, buffer int) *Publisher { return &amp;Publisher{ buffer: buffer, timeout: publishTimeout, subscribers: make(map[subscriber]topicFunc), } } // 添加一个新的订阅者，订阅全部主题 func (p *Publisher) Subscribe() chan interface{} { return p.SubscribeTopic(nil) } // 添加一个新的订阅者，订阅过滤器筛选后的主题 func (p *Publisher) SubscribeTopic(topic topicFunc) chan interface{} { ch := make(chan interface{}, p.buffer) p.m.Lock() p.subscribers[ch] = topic p.m.Unlock() return ch } // 退出订阅 func (p *Publisher) Evict(sub chan interface{}) { p.m.Lock() defer p.m.Unlock() delete(p.subscribers, sub) close(sub) } // 发布一个主题。遍历所有订阅者，将消息发送到订阅者通道 func (p *Publisher) Publish(v interface{}) { p.m.RLock() defer p.m.RUnlock() var wg sync.WaitGroup for sub, topic := range p.subscribers { wg.Add(1) go p.sendTopic(sub, topic, v, &amp;wg) } wg.Wait() } // 发布主题，可以容忍一定的超时。其实就是将发布的消息发送到订阅者通道中 func (p *Publisher) sendTopic(sub subscriber, topic topicFunc, v interface{}, wg *sync.WaitGroup) { defer wg.Done() // 存在订阅回调，但是回调失败，直接返回 if topic != nil &amp;&amp; !topic(v) { return } // 将消息发送到订阅通道中，超时退出 select { case sub &lt;- v: case &lt;-time.After(p.timeout): } } // 关闭发布者对象，同时关闭所有的订阅者通道 func (p *Publisher) Close() { p.m.Lock() defer p.m.Unlock() for sub := range p.subscribers { delete(p.subscribers, sub) close(sub) } } // main.go package main import ( &#34;fmt&#34; &#34;github.com/lwlwilliam/test/go/pubsub&#34; &#34;os&#34; &#34;os/signal&#34; &#34;strings&#34; &#34;syscall&#34; &#34;time&#34; ) func main() { p := pubsub.NewPublisher(100*time.Millisecond, 5) defer p.Close() all := p.Subscribe() world := p.SubscribeTopic(func(v interface{}) bool { if s, ok := v.(string); ok { return strings.Contains(s, &#34;world&#34;) } return false }) p.Publish(&#34;Hello world 1&#34;) p.Publish(&#34;Hello william 2&#34;) p.Publish(&#34;Hello world 3&#34;) p.Publish(&#34;Hello world 4&#34;) p.Publish(&#34;Hello world 5&#34;) p.Publish(&#34;Hello world 6&#34;) // 由于 all 通道满了，所以 all 会丢失该消息 p.Publish(&#34;Hello world 7&#34;) // 由于 world 通道也满了，所以 all 和 world 均会丢失该消息 go func() { for msg := range all { fmt.Println(&#34;all:&#34;, msg) } }() go func() { for msg := range world { fmt.Println(&#34;world:&#34;, msg) } }() time.Sleep(3 * time.Second) p.Publish(&#34;Hello world 8&#34;) // 正常情况下，睡眠 3 秒后，all 和 world 通道都清空缓存了，所以 all 和 world 均会订阅成功 // Ctrl+C 退出 sig := make(chan os.Signal, 1) signal.Notify(sig, syscall.SIGINT, syscall.SIGTERM) fmt.Printf(&#34;quit (%v)\n&#34;, &lt;-sig) } 生产者/消费者模型和订阅/发布模型的关系，类似于网络协议中的&quot;pull&quot;协议和&quot;push&quot;协议；生产者/消费者模型的数据传输不需要生产者发送给消费者，而是消费者主动&quot;pull&quot;数据；订阅/发布模型需要发布者将数据&quot;push&quot;给订阅者。

Master-Worker 模式的核心思想是 Master 进程和 Worker 进程各自分担各自的任务，协同完成信息处理的模式。
Master 进程用于管理维护 Worker 进程，而 Worker 进程则用于处理业务，如维持各自的客户端连接。
以下是用 PHP 实现的简单的 Master-Worker 守护多进程模式。
&lt;?php declare(ticks=1); class Worker { public static $count = 10; public static $children = []; public static function runAll() { static::runMaster(); static::monitor(); } /** * 主进程转为守护进程，这里的要点是 fork 两次，并且设置会话 id。一般情况下 fork 一次就够了，System-V 系统需要特殊处理 */ private static function runMaster() { // 确保进程有最大操作权限 umask(0); $pid = pcntl_fork(); if ($pid &gt; 0) { exit; } else { if ($pid &lt; 0) { throw new Exception(&#39;fork master failed&#39;); } } // 守护进程关键，脱离终端 if (posix_setsid() === -1) { throw new Exception(&#39;master setsid failed&#39;); } // 具体原因看&#34;守护进程&#34;一文 $pid = pcntl_fork(); if ($pid &gt; 0) { exit; } else { if ($pid &lt; 0) { throw new Exception(&#39;fork master failed&#39;); } } pcntl_signal(SIGTERM, &#39;static::sig_handler&#39;); cli_set_process_title(&#39;master process&#39;); // worker 进程 for ($i = 0; $i &lt; static::$count; $i++) { static::runWorker(); } } private static function sig_handler($signo) { foreach (static::$children as $child) { posix_kill($child, SIGKILL); } echo &#34;exit
&#34;; exit; } /* * 创建 Worker 进程 */ private static function runWorker() { umask(0); $pid = pcntl_fork(); if ($pid &gt; 0) { echo &#34;
worker $pid is running.
&#34;; static::$children[$pid] = $pid; } else { if ($pid == 0) { static::$children[getmypid()] = getmypid(); if (posix_setsid() === -1) { throw new Exception(&#39;worker setsid failed&#39;); } cli_set_process_title(&#39;worker process&#39;); echo &#34;Hello world: &#34; . getmypid() . &#34;
&#34;; sleep(20); unset(static::$children[getmypid()]); exit; } else { throw new Exception(&#39;fork worker process failed&#39;); } } } // 监控 worker，如果有进程退出，则重新 fork 一个 worker 进程 private static function monitor() { while ($pid = pcntl_wait($status)) { if ($pid == -1 || $pid == $status) { unset(static::$children[$pid]); break; } else { static::runWorker(); } } } } Worker::runAll();

在 OSTEP 上看到一段有意思的代码：
// p4.c #include &lt;stdio.h&gt; #include &lt;stdlib.h&gt; #include &lt;unistd.h&gt; #include &lt;string.h&gt; #include &lt;fcntl.h&gt; #include &lt;sys/wait.h&gt; int main() { int rc = fork(); if (rc &lt; 0) { fprintf(stderr, &#34;fork failed\n&#34;); exit(1); } else if (rc == 0) { close(STDOUT_FILENO); close(STDERR_FILENO); open(&#34;./p4.output&#34;, O_CREAT|O_WRONLY|O_TRUNC, S_IRWXU); open(&#34;./p4.error&#34;, O_CREAT|O_WRONLY|O_TRUNC, S_IRWXU); char *myargs[3]; myargs[0] = strdup(&#34;wc&#34;); myargs[1] = strdup(&#34;p4.c&#34;); // 如果将 p4.c 改成不存在的文件，标准错误就会写入到 p4.error 文件中 myargs[2] = NULL; execvp(myargs[0], myargs); } else { int rc_wait = wait(NULL); } return 0; } 以上程序执行结果如下：
$ gcc p4.c $ ./a.out $ cat p4.output 31 69 681 p4.c 可以发现以上程序并没有显式的将结果输出到屏幕，而是写入到 p4.output 文件了；同理，将程序中的 p4.c 改成不存在的文件，错误信息会写入到 p4.error 文件中。
跟以下 fprintf 这种显式指定输出文件的方式不一样，以上程序并没有显式指定标准输出为 p4.output、标准错误为 p4.error。
#include &lt;stdio.h&gt; int main() { FILE *fp = fopen(&#34;Hello&#34;, &#34;w&#34;); fprintf(fp, &#34;Hello world&#34;); return 0; } 这是由于 STDIN_FILENO, STDOUT_FILENO, STDERR_FILENO 的默认值分别为 0，1，2。而 Unix 系统从 0 开始查找自由的文件描述符，当 close(STDOUT_FILENO) 之后，1 变得不可用的，而通过 open() 调用打开 p4.output 文件后，该文件描述符就会对应首先被 close 的 STDOUT_FILENO；同理，p4.error 文件的文件描述符对应 STDERR_FILENO。因此，执行后续程序时，标准输出和标准错误就会分别重定向到 p4.output 和 p4.error 文件中。
Unix 管道就是以类似的方式实现的，但它用的是 pipe() 系统调用。这种情况下，一个进程的输出连接到一个内核 pipe（也就是队列）；另一个进程的输入连接到同一个管道；因此，一个进程的输出会无缝地作为下一个（进程）的输入。
